            after(() => {
                if (name == "resimulate") {
                    this.calculateWireData();
                }
            });
        }))

        if (this.enableAutoSimulation) {
            this.calculateWireData();
        }
        this.taskQueueStore.checkAndFixMas(this.masStore.mas);
